# Explorer · S42-T1-A-E2: rutas PASS / breach / MISSING según instruction
def assess(record: dict) -> str:
    required = {'case_id', 'extra_policy', 'json_schema', 'valid_fixture', 'business_rule'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if ((not (record["extra_policy"] == "allow" and not record["business_rule"])) and not record.get("__adv")) else "REJECT_SCHEMA"

